#include <iostream>

#define ROWS 3
#define COLS 3

bool areMatricesEqual(int mat1[ROWS][COLS], int mat2[ROWS][COLS], int rows, int cols) {
    for (int i = 0; i < rows; ++i) {
        for (int j = 0; j < cols; ++j) {
            if (mat1[i][j] != mat2[i][j]) {
                return false;
            }
        }
    }
    return true;
}

void printMatrix(int mat[ROWS][COLS], int r, int c) {
    for (int i = 0; i < r; ++i) {
        for (int j = 0; j < c; ++j) {
            std::cout << mat[i][j] << (j == c - 1 ? "" : " ");
        }
        std::cout << std::endl;
    }
}

int main() {
    int matrixA[ROWS][COLS] = {
        {1, 2, 3},
        {4, 5, 6},
        {7, 8, 9}
    };

    int matrixB[ROWS][COLS] = {
        {1, 2, 3},
        {4, 5, 6},
        {7, 8, 9}
    };

    int matrixC[ROWS][COLS] = {
        {1, 2, 3},
        {4, 0, 6},
        {7, 8, 9}
    };

    std::cout << "Test Case 1 (A vs B, 3x3): " << (areMatricesEqual(matrixA, matrixB, 3, 3) ? "Equal" : "Not Equal") << std::endl;
    std::cout << "Test Case 2 (A vs C, 3x3): " << (areMatricesEqual(matrixA, matrixC, 3, 3) ? "Equal" : "Not Equal") << std::endl;
    std::cout << "Test Case 3 (A vs B, 2x2): " << (areMatricesEqual(matrixA, matrixB, 2, 2) ? "Equal" : "Not Equal") << std::endl;

    // The following calls are expected to cause undefined behavior due to out-of-bounds access.
    // Their output cannot be reliably predicted, but they demonstrate the robustness flaw.
    std::cout << "Test Case 4 (A vs B, 4x3 - OOB): " << (areMatricesEqual(matrixA, matrixB, 4, 3) ? "Equal" : "Not Equal") << std::endl;
    std::cout << "Test Case 5 (A vs C, 3x4 - OOB): " << (areMatricesEqual(matrixA, matrixC, 3, 4) ? "Equal" : "Not Equal") << std::endl;

    return 0;
}
